mapper.select:
SELECT
TO_CHAR(collected_at, 'HH24:MI') AS time_label,
COALESCE(
EXTRACT(EPOCH FROM (collected_at - LAG(collected_at) OVER (ORDER BY collected_at))) / 60.0,
0.0
) AS interval_minutes
FROM

WHERE instance_id = #{instanceId}
AND collected_at >= #{startTime} AND collected_at  <=  #{endTime}
ORDER BY collected_at

SELECT checkpoint_raw_id AS id, TO_CHAR(collected_at, 'HH24:MI') AS timestamp, checkpoint_type AS type, COALESCE(checkpoint_write_time, 0.0) AS writeTime, COALESCE(checkpoint_sync_time, 0.0) AS syncTime, COALESCE(checkpoint_write_time + checkpoint_sync_time, 0.0) AS totalTime, CONCAT(ROUND(wal_bytes / 1048576.0, 2), ' MB') AS walGenerated, COALESCE(wal_files_added, 0) AS walFilesAdded, COALESCE(wal_files_removed, 0) AS walFilesRemoved, CONCAT(ROUND(checkpoint_distance / 1048576.0, 2), ' MB') AS checkpointDistance, COALESCE(buffers_checkpoint, 0) AS buffersWritten, COALESCE(buffers_backend, 0) AS buffersBackend, COALESCE(avg_buffers_per_sec, 0.0) AS avgBuffersPerSec, CASE WHEN checkpoint_write_time + checkpoint_sync_time > 30 THEN '위험' WHEN checkpoint_write_time + checkpoint_sync_time > 15 THEN '주의' ELSE '정상' END AS status FROM checkpoint_raw WHERE instance_id = #{instanceId} AND collected_at >= #{startTime} AND collected_at <= #{endTime}
AND CASE WHEN checkpoint_write_time + checkpoint_sync_time > 30 THEN '위험' WHEN checkpoint_write_time + checkpoint_sync_time > 15 THEN '주의' ELSE '정상' END IN
#{status}
ORDER BY collected_at DESC
